INSERT INTO oficios_cvm (fundo_id, origem, numero, assunto, teor, recebido_em, prazo_resposta, status, resposta, respondido_por, respondido_em) VALUES
(7, 'CVM', 'Ofício nº 145/2026/CVM/SIN/GIFI', 'Pedido de esclarecimentos — desenquadramento por concentração', 'Nos termos do art. 60 da Res. CVM 175, solicitamos esclarecimentos sobre a posição do ativo NORD3 acima do limite de 10% do PL por ativo, bem como o plano de reenquadramento e as providências do administrador fiduciário.', '2026-07-02', '2026-07-13', 'Recebido', NULL, NULL, NULL),
(NULL, 'CVM', 'Ofício Circular nº 3/2026/CVM/SIN', 'Orientações sobre marcação a mercado de ativos ilíquidos', 'Orientações gerais aos administradores fiduciários sobre metodologia e governança de precificação de ativos sem fonte primária líquida, incluindo a documentação das atas de comitê.', '2026-06-24', NULL, 'Ciente', NULL, 'Vinicius Fernandes', '2026-06-25 10:15:00'),
(2, 'ANBIMA', 'Solicitação ANBIMA nº 887/2026', 'Divergência nas estatísticas de maio', 'A base de dados de maio apresentou divergência entre o PL informado e o PL do informe diário do dia 29/05. Favor confirmar o valor correto.', '2026-06-08', '2026-06-22', 'Respondido', 'Confirmado o PL do informe diário (R$ 93,4 mi); a divergência decorreu de resgate processado após o corte. Base retificada.', 'Vinicius Fernandes', '2026-06-18 14:40:00');
